A debounce function delays the execution of a function until after a specified time has passed without it being called again, useful for optimizing events like search inputs or window resizing.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Example usage:
const handleSearch = (query) => {
  console.log('Searching for:', query);
};

const debouncedSearch = debounce(handleSearch, 300);

// Simulate user typing
debouncedSearch('a');
debouncedSearch('ab');
debouncedSearch('abc'); // Only this call will trigger the search after 300ms of inactivity
```
